Something like:

    def maybe_async(fn):
        @wraps(fn)
        def new_fn(*args, **kwargs):
            output = Future()
            try:
                result = fn(*args, **kwargs)
            except Exception:
                output.set_exc_info(*sys.exc_info())
            else:
                if gen.is_future(result):
                    output = result
                else:
                    output.set_result(result)
            return output
        return new_fn

